import requests
import json

class KongAdminAPI:
    def __init__(self, kong_admin_url):
        self.kong_admin_url = kong_admin_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'Content-Type': 'application/json'})
    
    def create_service(self, service_name, url, protocol='http'):
        """Create a service in Kong"""
        service_data = {
            "name": service_name,
            "url": url,
            "protocol": protocol
        }
        
        response = self.session.post(
            f"{self.kong_admin_url}/services",
            json=service_data
        )
        
        if response.status_code == 201:
            print(f"Service {service_name} created successfully")
            return response.json()
        else:
            print(f"Failed to create service {service_name}: {response.text}")
            return None
    
    def create_route(self, service_id, hosts=None, paths=None, methods=None):
        """Create a route for a service"""
        route_data = {
            "service": {"id": service_id}
        }
        
        if hosts:
            route_data["hosts"] = hosts
        if paths:
            route_data["paths"] = paths
        if methods:
            route_data["methods"] = methods
        
        response = self.session.post(
            f"{self.kong_admin_url}/routes",
            json=route_data
        )
        
        if response.status_code == 201:
            print("Route created successfully")
            return response.json()
        else:
            print(f"Failed to create route: {response.text}")
            return None
    
    def create_upstream(self, upstream_name, algorithm='round-robin'):
        """Create an upstream in Kong"""
        upstream_data = {
            "name": upstream_name,
            "algorithm": algorithm
        }
        
        response = self.session.post(
            f"{self.kong_admin_url}/upstreams",
            json=upstream_data
        )
        
        if response.status_code == 201:
            print(f"Upstream {upstream_name} created successfully")
            return response.json()
        else:
            print(f"Failed to create upstream {upstream_name}: {response.text}")
            return None
    
    def create_target(self, upstream_id, target, port=8000):
        """Create a target for an upstream"""
        target_data = {
            "target": target,
            "port": port
        }
        
        response = self.session.post(
            f"{self.kong_admin_url}/upstreams/{upstream_id}/targets",
            json=target_data
        )
        
        if response.status_code == 201:
            print(f"Target {target} added to upstream {upstream_id}")
            return response.json()
        else:
            print(f"Failed to add target {target}: {response.text}")
            return None
    
    def create_rate_limiting_plugin(self, service_id, limit=1000, window_size=60):
        """Create rate limiting plugin for a service"""
        plugin_data = {
            "name": "rate-limiting",
            "config": {
                "limit": [limit],
                "window_size": [window_size],
                "window_type": "sliding",
                "algorithm": "fixed-window",
                "retry_after_jitter_max": 1
            }
        }
        
        response = self.session.post(
            f"{self.kong_admin_url}/services/{service_id}/plugins",
            json=plugin_data
        )
        
        if response.status_code == 201:
            print("Rate limiting plugin created successfully")
            return response.json()
        else:
            print(f"Failed to create rate limiting plugin: {response.text}")
            return None
    
    def create_jwt_plugin(self, service_id):
        """Create JWT plugin for a service"""
        plugin_data = {
            "name": "jwt",
            "config": {
                "claims_to_verify": ["exp"],
                "key_claim_name": "iss",
                "secret_is_base64": False,
                "run_on_preflight": True
            }
        }
        
        response = self.session.post(
            f"{self.kong_admin_url}/services/{service_id}/plugins",
            json=plugin_data
        )
        
        if response.status_code == 201:
            print("JWT plugin created successfully")
            return response.json()
        else:
            print(f"Failed to create JWT plugin: {response.text}")
            return None

